
CREATE TABLE MAJOR(
    MAJOR_CODE CHAR(4) PRIMARY KEY ,
    MAJOR_NAME  VARCHAR(60),
    DEPARTMENT VARCHAR(60),
    DIVISION VARCHAR(50)
);

create table CLUB(
	club_code varchar(6)  primary key ,
	Name varchar(50),
	DESCRIPTION varchar(3000), 
	SUMMARY varchar(300), 
	FEE decimal(2,0)
);

create table STUDENT(
	STUDENT_ID varchar(10)  primary key ,
	FIRST_NAME varchar(50),
	LAST_NAME varchar(50),
	PHONE VARCHAR(12),
	SHIRT_SIZE VARCHAR(3),
	CITY VARCHAR(25),
	STATE CHAR(2),
	ZIP CHAR(5),
	EMAIL VARCHAR(21), 
	MAJOR_CODE char(4) references major
);

create table club_member(
	CLUB_CODE varchar(6) references CLUB,
	STUDENT_ID varchar(10)  references STUDENT,
	POSITION varchar(15),
	primary key (club_code, STUDENT_ID)
);


create table EVENT(
	EVENT_ID int primary key ,
	NAME varchar(200),
	BEGIN_TIME date,
	END_TIME date,
	LOCATION varchar(100),
	THEME varchar(20),
	CATEGORY varchar(32),
	club_code varchar(6) references CLUB,
	DESCRIPTION varchar(3000),
	BUDGET decimal(5)
);

create table BUDGET(
	EVENT_ID int references EVENT,
	ACCOUNT VARCHAR(30),
	AMOUNT decimal(3,0),
	DESCRIPTION VARCHAR(125),
	primary key(EVENT_ID, account)
);

create table EXPENSE(
	EXPENSE_ID int primary key,
	EXPENSE_DATE DATE,
	EVENT_ID int references EVENT,
	STUDENT_ID varchar(10)  references STUDENT,
	AMOUNT decimal(5,2),
	ACCOUNT VARCHAR(30)
);













