(3308929,'Bollywood Karaoke Dance Party',cast('2019-04-12 19:00' as date),cast('2019-04-12 21:00' as date),'Edge Cafe','Social',NULL,'SACC','For SPW, SACC is hosting a Bollywood Karaoke Dance Party in the Edge Cafe!'||chr(10)||'Sing and dance with us! '||chr(10)||'Catering by Royal Indian Grill. '||chr(10)||' ',610),
(3315866,'The Mat Presents: The Wrecks',cast('2019-04-12 19:00' as date),cast('2019-04-12 20:30' as date),'The Mat / Parker Commons','Social',NULL,'SAA','Join us at 7pm in The Mat (formally known as Parker Commons) for The Wrecks, a Los Angeles-based indie rock band. Popcorn and pizza will be served.'||chr(10)||' '||chr(10)||'There will be a Cash Bar for 21+ with two forms of ID.'||chr(10)||' '||chr(10)||'Zach Ceme ''19 will be taking the stage as our supporting act at 7:15pm with the Wrecks on at 8pm.',275),
(3327910,'Delta Upsilon 2000s Social',cast('2019-04-20 16:00' as date),cast('2019-04-20 19:00' as date),'Delta Upsilon','Social',NULL,'DU','We would like to host an event at the Delta Upsilon house on Saturday, April 20th from 4pm to 8 pm. The event is 2000s themed so the music and outfits will reflect that decade. '||chr(10)||' ',240),
