(562340,'Spring 2015 Student Involvement Fair',cast('2015-01-28 17:00' as date),cast('2015-01-28 19:00' as date),'Huntington Gym','Social',NULL,'SGA','THE STUDENT INVOLVEMENT FAIR'||chr(10)||'Wednesday, January 28th'||chr(10)||''||chr(10)||'From 5:00 P.M. to 7:00 P.M.'||chr(10)||'Location: Huntington Gym'||chr(10)||' '||chr(10)||''||chr(10)||'More than 200 organizations from ALANA, CLSI, COVE, the Office of the Chaplains, Club Sports, and more are participating in the student involvement fair to get you involved on campus! Try new things, meet new people, explore your interests! Check out all the different booths, and sign up for any groups you may be interested in. If you have any questions, please reach out to the SGA Liaison to Student Organizations, David Kim (sgaliaison@hudson.edu).',350),
(564213,'Democracy Matters Brown Bag',cast('2015-03-05 11:30' as date),cast('2015-03-05 13:30' as date),'O''Connor Campus Center Television Room','Thoughtful Learning',NULL,'DM','Democracy Matters features Political Science Professor Michael Johnston as he addresses the Deeper Corruptions: Political Money, Inequality, and the Credibility of Democracy.'||chr(10)||' '||chr(10)||'Come join us for lunch and enjoy thought provoking discussion.',null),
