(822228,'Mock Trial Tournaments',cast('2016-01-29 12:00' as date),cast('2016-01-31 20:45' as date),'Ithaca College','Thoughtful Learning',NULL,'MT','Mock Trial tournament to Ithaca College and University of Buffalo. ',275),
