(230541,'CAB Take Two: The Twilight Saga: Breaking Dawn - Part 2',cast('2013-02-22 22:00' as date),cast('2013-02-22 23:45' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two presents The Twilight Saga: Breaking Dawn - Part 2:'||chr(10)||'After the birth of Renesmee, the Cullens gather other vampire clans in order to protect the child from a false allegation that puts the family in front of the Volturi.'||chr(10)||'from imdb.com',null),
(244418,'CAB Take Two: Zero Dark Thirty',cast('2013-03-23 22:00' as date),cast('2013-03-23 22:45' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Movies presents:'||chr(10)||'Zero Dark Thirty at 7:00PM and Lincoln at 10:00PM in Love Auditorium on Friday, March 22nd, and again at opposite times on Saturday, March 23rd.'||chr(10)||'Zero Dark Thirty:'||chr(10)||'A chronicle of the decade-long hunt for al-Qaeda terrorist leader Osama bin Laden after the September 2001 attacks, and his death at the hands of the Navy S.E.A.L. Team 6 in May 2011.'||chr(10)||'Lincoln:'||chr(10)||'As the Civil War continues to rage, America''s president struggles with continuing carnage on the battlefield and as he fights with many inside his own cabinet on the decision to emancipate the slaves.'||chr(10)||' ',null),
(285845,'CAB Take Two: Now You See Me',cast('2013-09-06 22:00' as date),cast('2013-09-06 22:45' as date),'Love Auditorium (Olin 300)',NULL,'Movie/Film','SAA','CAB Take Two Movies presents: The Great Gatsby at 7:00PM and Now You See Me at 10:00PM in Love Auditorium on Friday, Sept 6th, and again at opposite times on Saturday, Sept 7th.'||chr(10)||'The Great Gatsby (Fri:7pm, Sat:10pm): A Midwestern war veteran finds himself drawn to the past and lifestyle of his millionaire neighbor.'||chr(10)||'Now You See Me (Fri:10 pm, Sat:pm): An FBI agent and an Interpol detective track a team of illusionists who pull off bank heists during their performances and reward their audiences with the money.    ',null),
(289256,'CAB Take Two: Man of Steel',cast('2013-09-13 22:00' as date),cast('2013-09-13 22:45' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Movies presents SUPER HERO WEEKEND:Iron Man 3 at 7:00PM and Man of Steel at 10:00PM in Love Auditorium on Friday, Sept 13th, and again at opposite times in on Saturday, Sept 14th.'||chr(10)||'Iron Man 3 (Fri 7pm and Sat 10pm)'||chr(10)||'When Tony Stark''s world is torn apart by a formidable terrorist called the Mandarin, he starts an odyssey of rebuilding and retribution. (starring Robert Downey Jr., Guy Pearce, Gwyneth Paltrow)'||chr(10)||'Man of Steel (Fri 10pm and Sat 7pm)'||chr(10)||'A young itinerant worker is forced to confront his secret extraterrestrial heritage when Earth is invaded by members of his race. (starring Henry Cavill, Amy Adams, Michael Shannon)'||chr(10)||' '||chr(10)||'from imdb.com'||chr(10)||' ',null),
(299679,'CAB Take Two: Hangover 3',cast('2013-09-28 22:00' as date),cast('2013-09-28 22:30' as date),'Love Auditorium',NULL,'Movie/Film','SAA','CAB Take Two Movies presents: Hangover 3 at 7:00PM and Fast and Furious 6 at 10:00PM in Love Auditorium on Friday, Sept 27th, and again at opposite times in on Saturday, Sept 28th.'||chr(10)||'Hangover 3 (Starring Bradley Cooper, Zach Galifianakis, Ed Helms)'||chr(10)||'When one of their own is kidnapped by an angry gangster, the Wolf Pack must track down Mr. Chow, who has escaped from prison and is on the lam.'||chr(10)||'Fast and Furious 6 (Starring Vin Diesel, Paul Walker, Dwayne Johnson)'||chr(10)||'Hobbs has Dom and Brian reassemble their crew in order to take down a mastermind who commands an organization of mercenary drivers across 12 countries. Payment? Full pardons for them all.'||chr(10)||' '||chr(10)||' ',null),
